import{_ as a,a as d,b as t,c as i,d as n,e as o,f as s,g as r}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as p,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/federated-distributed-index.md","filePath":"th-TH/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"th-TH/Other/federated-distributed-index.md"};function b(m,e,f,g,x,q){return p(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index ช่วยให้ ImgBed sites หลายแห่ง share file lists กันได้</p><p>พูดง่าย ๆ:</p><ul><li>คุณ share selected folders จาก site ของคุณให้คนอื่นได้</li><li>คุณ join node อื่นและ sync shared file list ของ node นั้นเข้ามาใน admin panel ของคุณได้</li><li>Federated files มีไว้สำหรับ browsing, searching และเปิด links เป็นหลัก ไม่ได้ re-upload เข้า storage ของคุณเอง</li></ul><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>Page มีสาม tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>Enable node ของคุณ, confirm public domain, เลือก shared folders และ update outbound index</td></tr><tr><td>Nodes I Joined</td><td>Manage ImgBed nodes อื่นที่คุณ join</td></tr><tr><td>Nodes Joining Me</td><td>Manage requests จากคนอื่นที่ต้องการ join node ของคุณ</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>เปิด <code>Local Node</code></li><li>เปิด <code>Enable</code></li><li>เลือก folders ที่ต้องการ share ใน <code>Sync folders</code></li><li>คลิก <code>Update Outbound Index</code></li><li>ถ้า ImgBed detect domain change ให้ confirm ว่า current domain ถูกต้องก่อนทำต่อ</li></ol><p>เลือก sync folders ได้หลายรายการ</p><p>ถ้า sync folder list ว่าง จะ share ทุก folders</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain คือ site URL ที่ nodes อื่นใช้ access node ของคุณ</p><p>ImgBed detect ให้อัตโนมัติ ไม่ต้องพิมพ์เอง ครั้งแรกที่ update index ImgBed จะถามว่า current access URL คือ production domain หรือไม่</p><p>ถ้าเปลี่ยน domain ภายหลัง การ update index จะถาม confirmation อีกครั้ง</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders กำหนดว่า files ใด share ให้ federation nodes</p><p>เช่น ถ้าเลือกเฉพาะ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Nodes อื่นจะเห็นเฉพาะ files ในสอง directories นี้</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Update file list ที่ nodes อื่น sync จากคุณได้</p><p>ใช้เมื่อ:</p><ul><li>Enable federation ครั้งแรก</li><li>Upload files ที่ต้องการ share</li><li>เปลี่ยน sync folders</li><li>เปลี่ยน public domain และต้อง confirm</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> คือที่ subscribe nodes อื่น</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="request-to-join-another-node" tabindex="-1">Request To Join Another Node <a class="header-anchor" href="#request-to-join-another-node" aria-label="Permalink to &quot;Request To Join Another Node&quot;">​</a></h3><ol><li>ขอ invitation link จาก owner อีกฝั่ง</li><li>Paste ใน input box</li><li>คลิก <code>Request to Join</code></li><li>รอ owner อีกฝั่ง approve ใน admin panel</li></ol><p>หลัง approval แล้ว node status จะเป็น approved</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> sync file lists จาก nodes ที่คุณ joined</p><p>ใช้เมื่อ:</p><ul><li>Owner อีกฝั่งเพิ่ง approve request ของคุณ</li><li>Owner อีกฝั่งบอกว่า shared content update แล้ว</li><li>ต้องการ refresh joined federation file lists ทั้งหมด</li></ul><p>ถ้าต้องการ update node เดียว ให้คลิก <code>Update Index</code> บน node card นั้น</p><p><img src="'+t+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>ถ้าไม่ต้องการ sync node แล้ว ให้คลิก <code>Unsubscribe</code></p><p>หลัง unsubscribe federated index ของ node นั้นจะถูกลบออกจาก local site ของคุณ</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> คือที่จัดการ requests จากคนอื่น</p><p><img src="'+i+'" alt="Nodes joining me" loading="lazy"></p><h3 id="generate-invitation-link" tabindex="-1">Generate Invitation Link <a class="header-anchor" href="#generate-invitation-link" aria-label="Permalink to &quot;Generate Invitation Link&quot;">​</a></h3><ol><li>ตรวจว่า local node enabled</li><li>คลิก <code>Update Outbound Index</code> อย่างน้อยหนึ่งครั้งเพื่อให้ ImgBed confirm public domain</li><li>เปิด <code>Nodes Joining Me</code></li><li>คลิก <code>Reset Invitation Link</code></li><li>Copy invitation link แล้วส่งให้ owner อีกฝั่ง</li></ol><p>ถ้า invitation link ว่าง มักแปลว่ายังไม่ได้ confirm public domain กลับไปที่ <code>Local Node</code> แล้วคลิก <code>Update Outbound Index</code></p><h3 id="handle-join-requests" tabindex="-1">Handle Join Requests <a class="header-anchor" href="#handle-join-requests" aria-label="Permalink to &quot;Handle Join Requests&quot;">​</a></h3><p>เมื่อมีคน submit request จะปรากฏใน list <code>Nodes Joining Me</code></p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>อนุญาตให้ node อีกฝั่ง sync shared file list ของคุณ</td></tr><tr><td>Reject</td><td>ปฏิเสธ join request</td></tr><tr><td>Delete</td><td>ลบ finished record</td></tr><tr><td>Check Status</td><td>ตรวจว่าอีกฝั่งยังรักษา relationship นี้อยู่หรือไม่</td></tr></tbody></table><p>หลัง approval อีกฝั่งยังต้องคลิก <code>Update Inbound Index</code> ก่อน shared files ของคุณจึงจะแสดงที่ฝั่งนั้น</p><p><img src="'+n+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>หลัง relationship approved ให้คลิก <code>Message</code> บน node card</p><p>Messages ใช้สื่อสารเกี่ยวกับ federation relationship เท่านั้น ไม่เปลี่ยน files, tags, directories หรือ permissions</p><p><img src="'+o+'" alt="Messages" loading="lazy"></p><h2 id="ดู-federated-files" tabindex="-1">ดู Federated Files <a class="header-anchor" href="#ดู-federated-files" aria-label="Permalink to &quot;ดู Federated Files&quot;">​</a></h2><p>หลัง sync เสร็จ กลับไปที่ admin file list</p><p>ด้านบนของ page ให้สลับระหว่าง local files และ federated files ใน federated files คุณ browse synced content ได้</p><p>Federated files ใช้สำหรับ viewing, searching, previewing และ copying links เป็นหลัก ไม่ใช่ local files จึง move, delete, retag หรือ back up จาก site ของคุณเองไม่ได้</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ทําไมระบบบอกให้-reapply-เพราะไม่มี-relationship-record" tabindex="-1">ทำไมระบบบอกให้ Reapply เพราะไม่มี Relationship Record? <a class="header-anchor" href="#ทําไมระบบบอกให้-reapply-เพราะไม่มี-relationship-record" aria-label="Permalink to &quot;ทำไมระบบบอกให้ Reapply เพราะไม่มี Relationship Record?&quot;">​</a></h3><p>มักหมายถึงอีกฝั่ง delete คุณและลบ record แล้ว relationship จึงหาไม่เจอ ให้ submit join request ใหม่</p><p><img src="'+r+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="ทําไม-join-แล้วไม่เห็น-files" tabindex="-1">ทำไม Join แล้วไม่เห็น Files? <a class="header-anchor" href="#ทําไม-join-แล้วไม่เห็น-files" aria-label="Permalink to &quot;ทำไม Join แล้วไม่เห็น Files?&quot;">​</a></h3><p>ตรวจว่า:</p><ol><li>Owner อีกฝั่ง approve request แล้ว</li><li>Owner อีกฝั่งคลิก <code>Update Outbound Index</code> แล้ว</li><li>คุณคลิก <code>Update Inbound Index</code> แล้ว</li><li>Sync folders ของ owner อีกฝั่งรวม directories ที่ต้องการ share</li></ol><h3 id="domain-change-detected-ควรทําอย่างไร" tabindex="-1">Domain Change Detected ควรทำอย่างไร? <a class="header-anchor" href="#domain-change-detected-ควรทําอย่างไร" aria-label="Permalink to &quot;Domain Change Detected ควรทำอย่างไร?&quot;">​</a></h3><p>ถ้าตอนนี้เปิด admin panel ผ่าน production domain ให้ confirm และ continue</p><p>ถ้าใช้ temporary address ให้ cancel แล้วเปิด admin panel ด้วย production domain จากนั้นลองใหม่</p><h3 id="empty-sync-folder-list-หมายถึงอะไร" tabindex="-1">Empty Sync Folder List หมายถึงอะไร? <a class="header-anchor" href="#empty-sync-folder-list-หมายถึงอะไร" aria-label="Permalink to &quot;Empty Sync Folder List หมายถึงอะไร?&quot;">​</a></h3><p>หมายถึง share ทุก folders</p><p>ถ้าต้องการ share เฉพาะบาง directories ให้เลือก folders เอง</p><h3 id="difference-between-outbound-and-inbound-index-updates" tabindex="-1">Difference Between Outbound and Inbound Index Updates <a class="header-anchor" href="#difference-between-outbound-and-inbound-index-updates" aria-label="Permalink to &quot;Difference Between Outbound and Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Update สิ่งที่คนอื่น sync จากฉันได้</td></tr><tr><td>Update Inbound Index</td><td>Update สิ่งที่ฉัน sync จากคนอื่น</td></tr></tbody></table>',78)])])}const _=l(u,[["render",b]]);export{k as __pageData,_ as default};
